#include <stdio.h>
#include <stdlib.h>
#include <string.h>

long long gcd_ll(long long a, long long b) {
    if (a < 0) a = -a;
    if (b < 0) b = -b;
    while (b) { long long t = a % b; a = b; b = t; }
    return a;
}

typedef struct { long long dx, dy; } Pair;

int pair_cmp(const void *a, const void *b) {
    const Pair *p = a, *q = b;
    if (p->dx != q->dx) return p->dx < q->dx ? -1 : 1;
    if (p->dy != q->dy) return p->dy < q->dy ? -1 : 1;
    return 0;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *x = malloc(N * sizeof(long long));
        long long *y = malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld %lld", &x[i], &y[i]);
        int best = 1;
        for (int i = 0; i < N; ++i) {
            int dup = 0;
            Pair *arr = malloc((N-1) * sizeof(Pair));
            int cnt = 0;
            for (int j = 0; j < N; ++j) if (j != i) {
                long long dx = x[j] - x[i];
                long long dy = y[j] - y[i];
                if (dx == 0 && dy == 0) { dup++; continue; }
                long long g = gcd_ll(dx, dy);
                dx /= g; dy /= g;
                if (dx < 0 || (dx == 0 && dy < 0)) { dx = -dx; dy = -dy; }
                arr[cnt].dx = dx; arr[cnt].dy = dy; cnt++;
            }
            if (cnt > 0) {
                qsort(arr, cnt, sizeof(Pair), pair_cmp);
                int cur = 1, localMax = 1;
                for (int k = 1; k < cnt; ++k) {
                    if (arr[k].dx == arr[k-1].dx && arr[k].dy == arr[k-1].dy) {
                        cur++;
                    } else {
                        if (cur > localMax) localMax = cur;
                        cur = 1;
                    }
                }
                if (cur > localMax) localMax = cur;
                if (localMax + dup + 1 > best) best = localMax + dup + 1;
            } else {
                if (dup + 1 > best) best = dup + 1;
            }
            free(arr);
        }
        printf("%d\n", best);
        free(x); free(y);
    }
    return 0;
}

