import java.io.*;
import java.util.*;

public class Main {
    static long gcd(long a, long b) {
        if (a < 0) a = -a;
        if (b < 0) b = -b;
        while (b != 0) {
            long t = a % b;
            a = b;
            b = t;
        }
        return a;
    }
    static class Pair {
        long dx, dy;
        Pair(long dx, long dy){ this.dx=dx; this.dy=dy; }
        @Override public int hashCode(){ return Objects.hash(dx, dy); }
        @Override public boolean equals(Object o){
            if(!(o instanceof Pair)) return false;
            Pair p=(Pair)o; return dx==p.dx && dy==p.dy;
        }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            long[] x = new long[N];
            long[] y = new long[N];
            for (int i = 0; i < N; i++) {
                st = new StringTokenizer(br.readLine());
                x[i] = Long.parseLong(st.nextToken());
                y[i] = Long.parseLong(st.nextToken());
            }
            int answer = 1;
            for (int i = 0; i < N; i++) {
                Map<Pair,Integer> map = new HashMap<>();
                int dup = 0;
                int localMax = 0;
                for (int j = 0; j < N; j++) if (j != i) {
                    long dx = x[j] - x[i];
                    long dy = y[j] - y[i];
                    if (dx == 0 && dy == 0) { dup++; continue; }
                    long g = gcd(dx, dy);
                    dx /= g; dy /= g;
                    if (dx < 0 || (dx == 0 && dy < 0)) { dx = -dx; dy = -dy; }
                    Pair p = new Pair(dx, dy);
                    int cnt = map.getOrDefault(p, 0) + 1;
                    map.put(p, cnt);
                    localMax = Math.max(localMax, cnt);
                }
                answer = Math.max(answer, localMax + dup + 1);
            }
            out.append(answer).append('\n');
        }
        System.out.print(out.toString());
    }
}

