const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let outputs = [];
function gcd(a, b) {
  a = Math.abs(a); b = Math.abs(b);
  while (b !== 0) { const t = a % b; a = b; b = t; }
  return a;
}
for (let t = 0; t < T; ++t) {
  const N = input[idx++];
  const points = [];
  for (let i = 0; i < N; ++i) {
    const x = input[idx++];
    const y = input[idx++];
    points.push([x, y]);
  }
  let best = 1;
  for (let i = 0; i < N; ++i) {
    const map = new Map();
    let dup = 0;
    let localMax = 0;
    const [xi, yi] = points[i];
    for (let j = 0; j < N; ++j) {
      if (i === j) continue;
      const [xj, yj] = points[j];
      let dx = xj - xi;
      let dy = yj - yi;
      if (dx === 0 && dy === 0) { dup++; continue; }
      const g = gcd(dx, dy);
